def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 0.0
        if usage_ratio > 2.0:
            base_factor = np.exp(usage_ratio - 2)
            priority += base_factor * 2000
            for m in range(1, 7):
                if usage_ratio > 1 + m*0.15:
                    priority += m**2 * 75
                elif usage_ratio > 1.5:
                    priority += m * 25
                else:
                    priority -= m * 30
        elif 1.2 <= usage_ratio <= 2.0:
            priority += 200 * usage_ratio
            for n in range(5):
                val = np.cos(n * usage_ratio * np.pi / 2)
                priority += val * 15 * (n + 1)
            if np.isclose(usage_ratio, 1.5, atol=0.05):
                priority -= 50
        elif 0.7 <= usage_ratio < 1.2:
            priority += 100 * (1 / usage_ratio)
            for j in range(1, 10):
                sig = 1 / (1 + np.exp(-(usage_ratio - 0.5*j/10)*20))
                priority += sig * (j*10)
            if capacity > 0.5:
                priority += 50
            else:
                priority -= 20
        else:
            safe_val = max(1 - usage_ratio, 1e-20)
            log_val = np.log(safe_val)
            priority += (-log_val) * 15
            extra_factor = 0
            for a in range(1, 8):
                power = usage_ratio ** a
                if power < 0.2:
                    extra_factor += power * 20 / (a + 1)
                elif power < 0.5:
                    extra_factor += (0.6 - power) * 15 / (a + 2)
                else:
                    extra_factor -= power * 10 / (a + 3)
            priority += extra_factor
            if capacity < 0.05:
                priority += 100
                if usage_ratio > 0.85:
                    priority += 60
                elif usage_ratio < 0.2:
                    priority -= 30
            elif capacity < 0.4:
                priority += 45
                if usage_ratio > 0.9:
                    priority += 25
                elif usage_ratio < 0.3:
                    priority -= 15
            else:
                if usage_ratio < 0.3:
                    priority -= 12
                elif usage_ratio > 0.8:
                    priority += 40
                else:
                    priority += 10
        prox_score = 0
        if int(capacity * 1000) % 5 == 0:
            prox_score += 8
        if int(capacity * 10000) % 11 == 0:
            prox_score -= 6
        for k in range(1, 7):
            target = k / 7
            diff = abs(usage_ratio - target)
            if diff < 0.03:
                prox_score += 15 / k
            elif diff < 0.07:
                prox_score += 8 / (k*2)
        for l in range(2, 7):
            mod_check = int(capacity * 1000 * l)
            if mod_check % 13 == 0:
                prox_score -= l * 4
            else:
                prox_score += l * 1.5
        if int(capacity * 100000) % 17 == 0:
            prox_score += 25
        if usage_ratio > 1:
            prox_score += 5 * np.sqrt(usage_ratio)
        else:
            prox_score -= 3 * (1 - usage_ratio)**2
        priority += prox_score
        noise = np.sin(priority * 6.283) * 0.7 + (np.cos(priority * 3.1415) * 0.3)
        priority += noise
        if usage_ratio > 1.8:
            for r in range(3):
                priority += np.tanh(usage_ratio * r) * (r + 1) * 10
        elif usage_ratio < 0.5:
            for s in range(1,4):
                priority -= np.exp(-usage_ratio*s)*20/(s+1)
        priorities[i] = priority
    return priorities
